import SwiftUI

struct GreetingView: View {
  let name: String
  var body: some View {
    VStack(spacing: 12) {
      Image(systemName: "hand.wave.fill")
        .font(.system(size: 48))
      Text("Hello, \(name)")
        .font(.title)
        .foregroundStyle(.primary)
    }
    .padding()
    .background(.regularMaterial)
    .clipShape(RoundedRectangle(cornerRadius: 16))
  }
}

// View tree is a struct value — cheap to create; the framework caches identity.
// `body` returns `some View` — opaque type hides the very specific generic type
// SwiftUI synthesizes (VStack<TupleView<...>>).

#Preview {
