}

// Vertical stack
VStack(alignment: .leading, spacing: 8) {
  Text("Title").font(.headline)
  Text("Subtitle").foregroundStyle(.secondary)
}

// Horizontal
HStack {
  Image(systemName: "star.fill")
  Text("Featured")
  Spacer() // pushes content left
  Text("4.8")
}

// Layered
ZStack(alignment: .topTrailing) {
  Image("hero")
  Text("NEW")
    .padding(6)
    .background(.red, in: Capsule())
    .foregroundStyle(.white)
    .padding(8)
}

// Lazy — only renders rows in viewport
ScrollView {
  LazyVStack(spacing: 12) {
    ForEach(0..<10_000, id: \.self) { i in
      Text("Row \(i)").padding()
    }
  }
}

// Grid (iOS 16+)
Grid(horizontalSpacing: 12, verticalSpacing: 8) {
  GridRow { Text("A"); Text("B"); Text("C") }
  GridRow { Text("1"); Text("2"); Text("3") }
}

// Built-in modifiers
Text("Hello")
  .font(.title)
  .foregroundStyle(.blue)
  .padding()
  .background(.yellow)
  .clipShape(RoundedRectangle(cornerRadius: 8))

// Modifier order matters
Text("A").padding().background(.red)   // red surrounds padding too
Text("A").background(.red).padding()   // red is tight around text, padding outside

// Custom ViewModifier
struct CardStyle: ViewModifier {
  func body(content: Content) -> some View {
    content
      .padding()
      .background(.regularMaterial)
      .clipShape(RoundedRectangle(cornerRadius: 16))
      .shadow(radius: 4, y: 2)
  }
}

extension View {
  func cardStyle() -> some View { modifier(CardStyle()) }
}

// Usage
VStack { Text("x"); Text("y") }
  .cardStyle()

// Conditional modifier — extension helper
extension View {
  @ViewBuilder
  func `if`<T: View>(_ condition: Bool, transform: (Self) -> T) -> some View {
    if condition { transform(self) } else { self }
  }
}
