// Typed route stack
struct Route: Hashable { let userId: String }

struct RootView: View {
  @State private var path: [Route] = []
  var body: some View {
    NavigationStack(path: $path) {
      List(users) { user in
        NavigationLink(value: Route(userId: user.id)) {
          Text(user.name)
        }
      }
      .navigationTitle("Users")
      .navigationDestination(for: Route.self) { route in
        UserDetailView(userId: route.userId)
      }
      .toolbar {
        Button("Deep link") {
          path = [Route(userId: "42")]
        }
      }
    }
  }
}

// Sidebar / content / detail
struct LibraryView: View {
  @State private var selectedFolder: Folder?
  @State private var selectedDoc: Doc?
  var body: some View {
    NavigationSplitView {
      List(folders, selection: $selectedFolder) { folder in
        Text(folder.name).tag(folder)
      }
    } content: {
      if let folder = selectedFolder {
        List(folder.docs, selection: $selectedDoc) { doc in
          Text(doc.title).tag(doc)
        }
      }
    } detail: {
      if let doc = selectedDoc { DocView(doc: doc) } else { Text("Select") }
    }
  }
}

struct Todo: Identifiable { let id: UUID; var title: String; var done: Bool }

struct TodoListView: View {
  @State var todos: [Todo] = []
  @State var search = ""
  var body: some View {
    List {
      Section("Pending") {
        ForEach($todos.filter { !$0.done.wrappedValue }) { $todo in
          Toggle(isOn: $todo.done) { Text(todo.title) }
            .swipeActions(edge: .trailing) {
              Button(role: .destructive) { delete(todo) } label: { Label("Delete", systemImage: "trash") }
            }
        }
      }
      Section("Done") {
        ForEach(todos.filter(\.done)) { todo in
          Text(todo.title).strikethrough()
        }
      }
    }
    .listStyle(.insetGrouped)
    .searchable(text: $search)
    .refreshable { await reload() }
    .toolbar {
      Button("Add") { todos.append(Todo(id: UUID(), title: "New", done: false)) }
    }
  }
  func delete(_ t: Todo) { todos.removeAll { $0.id == t.id } }
  func reload() async { /* ... */ }
}

// ForEach with non-Identifiable — pass key path
ForEach(0..<10, id: \.self) { i in Text("\(i)") }

struct ProfileCard: View {
  let user: User
  var body: some View {
    VStack(alignment: .leading) {
      Text(user.name).font(.title)
      Text(user.bio).foregroundStyle(.secondary)
